26	fn rbtdti_make_temp(label: &str) -> PathBuf {
27	    let dir = rbtdth_scratch_root().join(format!("rbtd-test-{}-{}", std::process::id(), label));
28	    std::fs::create_dir_all(&dir).unwrap();
29	    dir
30	}
