38	fn rbtdti_write_script(tt_dir: &PathBuf, name: &str, body: &str) {
39	    let path = tt_dir.join(name);
40	    std::fs::write(&path, format!("#!/bin/bash\n{}", body)).unwrap();
41	    #[cfg(unix)]
42	    {
43	        use std::os::unix::fs::PermissionsExt;
44	        std::fs::set_permissions(&path, std::fs::Permissions::from_mode(0o755)).unwrap();
45	    }
46	}
