50	#[test]
51	fn rbtdti_finds_matching_tabtarget() {
52	    let tmp = rbtdti_make_temp("find-match");
53	    let tt = rbtdti_make_tt_dir(&tmp);
54	    rbtdti_write_script(&tt, "rbw-cb.Bark.tadmor.sh", "exit 0\n");
55	
56	    let result = rbtdri_find_tabtarget(&tmp, "rbw-cb", "tadmor");
57	    assert!(result.is_ok());
58	    let path = result.unwrap();
59	    assert!(path.file_name().unwrap().to_str().unwrap() == "rbw-cb.Bark.tadmor.sh");
60	
61	    let _ = std::fs::remove_dir_all(&tmp);
62	}
